sys_script.description:
// STRY0074131
- FIX: CDS – Activity Log entries display on the Activity Tab of the Top Task where multiple subtasks with multi-OUs and Members were created in Serial
// RJ - STRY0062618 - added this script to create the multiple sub-processes.  If there is a parent, we will do the coding after insert.  If it is a child, we need to do some processing before insert and after insert.  This is the after insert Method

sys_script.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	var insertMultipleFunction = new Task_onInsert_Multiple_Sub_Tasks();

	// Movded this condition off the condition line and in here so I could add the worknote before insert on the parent.
	if(!current.parent.nil()){
		// RJ - STRY0062618 - added this script to create the multiple sub processes.
		// create the insertMultipleFunction object to Procoess multi sub task inserts
		if (!insertMultipleFunction.beforeInsertProcessing(current)){
			current.setAbortAction(true);
		}
	}
	else{
		// if this is a new item and the multiple select is on, then write an activity log to
		if(current.u_create_multiple_subtasks == true){
			var firstSubtoProcess = insertMultipleFunction.GetFirstSubTaskPrimaryAssignee(current);
			// RJ - STRY0063315	- this story descibes how to write the worknote.
			var sPrimaryAssigneeOUs = insertMultipleFunction.GetPrimaryOUAbbreviations(firstSubtoProcess.ArrayPrimaryAssignees);
			// RJ - STRY0063315	- this story descibes how to write the worknote.
			var sAssignedMemberNames = insertMultipleFunction.GetAssignedMemberNames(firstSubtoProcess.ArrayAssignedMembers);

			var assignedToName = 'Unassigned';
			if (!current.assigned_to.nil()){
				assignedToName = current.assigned_to.name;
			}
			var assignedPrimaryAssignee = 'Unassigned';
			if (!current.primary_assignee.nil()){
				assignedPrimaryAssignee = current.primary_assignee.office_abbreviation;
			}
			// STRY0074131 - STRY0074338 - FIX: CDS – Activity Log entries display on the Activity Tab of the Top Task 
			// Tasker number not set yet on a new task, so get it, but don't set it.  Let it get set later where it normally is
			var taskerNM = new TaskerDisplayValueConfiguration().setTaskerNumber(current);
			// changed to use comments b/c work notes seemed to be overwritten by a later update to work notes on the base task table
			current.comments = insertMultipleFunction.getWorkNote(taskerNM, assignedPrimaryAssignee, assignedToName, sPrimaryAssigneeOUs, sAssignedMemberNames, current.u_create_subtasks_in_serial);

		}
	}

})(current, previous);
